mapper.select:
SELECT MESSAGE_ID, ROOM_ID, ROOM_UUID, CLIENT_MESSAGE_UUID, SENDER_TYPE, SENDER_MEMBER_ID, SENDER_NAME_SNAPSHOT, MESSAGE_TYPE, CONTENT, CREATED_AT, READ_AT
FROM ( SELECT M.MESSAGE_ID, M.ROOM_ID, R.ROOM_UUID, M.CLIENT_MESSAGE_UUID, M.SENDER_TYPE, M.SENDER_MEMBER_ID, M.SENDER_NAME_SNAPSHOT, M.MESSAGE_TYPE, M.CONTENT, M.CREATED_AT, M.READ_AT
FROM CUSTOMER_CHAT_MESSAGE M
INNER JOIN CUSTOMER_CHAT_ROOM R ON R.ROOM_ID = M.ROOM_ID
WHERE R.ROOM_UUID = #{roomUuid}
AND M.MESSAGE_ID < #{beforeMessageId}
ORDER BY M.MESSAGE_ID DESC )
WHERE ROWNUM <= #{size}
ORDER BY MESSAGE_ID ASC

SELECT R.ROOM_UUID, R.VISITOR_TYPE, R.MEMBER_ID, R.GUEST_ID, R.CUSTOMER_NAME_SNAPSHOT AS CUSTOMER_NAME, R.ASSIGNED_ADMIN_ID, A.NICKNAME AS ASSIGNED_ADMIN_NICKNAME, R.STATUS, R.CUSTOMER_UNANSWERED_COUNT, R.ADMIN_UNREAD_COUNT, R.CUSTOMER_UNREAD_COUNT, R.LAST_MESSAGE_PREVIEW, R.LAST_MESSAGE_SENDER_TYPE, R.CREATED_AT, R.ACCEPTED_AT, R.LAST_MESSAGE_AT, R.CLOSED_AT FROM CUSTOMER_CHAT_ROOM R LEFT JOIN APP_MEMBER A ON A.MEMBER_ID = R.ASSIGNED_ADMIN_ID
R.STATUS = #{status}
ORDER BY CASE WHEN R.STATUS = 'WAITING' THEN 1 WHEN R.STATUS = 'CHATTING' THEN 2 ELSE 3 END, R.LAST_MESSAGE_AT DESC
